import { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';

export default function SavedDupes({ session }) {
  const [dupes, setDupes] = useState([]);
  const [original, setOriginal] = useState('');
  const [dupe, setDupe] = useState('');

  // Sapo hapet faqja, lexo të dhënat nga databaza
  useEffect(() => {
    if (session) {
      fetchDupes();
    }
  }, [session]);

  // READ: Merr vetëm të dhënat e këtij user-i
  const fetchDupes = async () => {
    const { data, error } = await supabase
      .from('saved_dupes')
      .select('*')
      .order('created_at', { ascending: false }); // I rendit nga më e reja
    
    if (error) console.error("Gabim gjatë leximit:", error);
    else setDupes(data);
  };

  // CREATE: Shto një produkt të ri në tabelë
  const addDupe = async (e) => {
    e.preventDefault();
    const { error } = await supabase
      .from('saved_dupes')
      .insert([
        { 
          user_id: session.user.id, 
          original_product: original, 
          dupe_product: dupe 
        }
      ]);

    if (error) {
      alert("Ndodhi një gabim: " + error.message);
    } else {
      setOriginal('');
      setDupe('');
      fetchDupes(); // Rifresko listën menjëherë pas shtimit
    }
  };

  return (
    <div style={{ padding: '20px', maxWidth: '600px', margin: '0 auto' }}>
      <h2>GlowAI - Produktet e mia</h2>
      <p>I loguar si: <strong>{session.user.email}</strong></p>
      <button onClick={() => supabase.auth.signOut()} style={{ marginBottom: '20px' }}>Dil nga llogaria (Log Out)</button>

      {/* Forma për të shtuar rekorde të reja */}
      <form onSubmit={addDupe} style={{ display: 'flex', gap: '10px', marginBottom: '30px' }}>
        <input 
          placeholder="Produkti i shtrenjtë..." 
          value={original} 
          onChange={(e) => setOriginal(e.target.value)} 
          required 
        />
        <input 
          placeholder="Dupe më i lirë..." 
          value={dupe} 
          onChange={(e) => setDupe(e.target.value)} 
          required 
        />
        <button type="submit">Ruaj</button>
      </form>

      {/* Lista ku shfaqen të dhënat */}
      <h3>Lista e Dupes të Ruajtura:</h3>
      {dupes.length === 0 ? (
        <p>Nuk ke asnjë produkt të ruajtur ende.</p>
      ) : (
        <ul style={{ textAlign: 'left' }}>
          {dupes.map((item) => (
            <li key={item.id} style={{ marginBottom: '10px' }}>
              ❌ <strong>{item.original_product}</strong> <br/>
              ✅ <em>{item.dupe_product}</em>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
